SELECT para_attributes 
FROM paragraphs 
WHERE paragraph_id = 1;

SELECT u.username 
FROM users u 
WHERE u.user_id NOT IN (SELECT c.user_id FROM collaborations c);

SELECT 
  (SELECT COUNT(page_id) FROM pages) AS total_pages,
  (SELECT COUNT(paragraph_id) FROM paragraphs) AS total_paragraphs;

SELECT COUNT(version_id) 
FROM document_versions 
WHERE created_by IN (SELECT user_id FROM collaborations);

SELECT COUNT(DISTINCT user_id) 
FROM collaborations 
WHERE doc_id = 0 AND is_active = 1;

SELECT version_details
FROM document_versions
WHERE created_by = 1 AND is_active = 1;
